/**
 * DebugPage - 调试页面
 * 用于开发和测试环境的调试工具集合
 * 对标 react-haven 的 DebugPage，功能保持一致
 */
import { FC, useCallback, useState } from "react";
import { useNavigate } from "react-router-dom";
import { useUser } from "@/hooks/useUser";
import { adminDeletePaypalId } from "@/http/userApi";
import { UserServiceCommonCode } from "@sitin/api-proto/gen/archat_api/user_api";
import { useTask } from "@/hooks/useTask";
import { isApp, openEmailClient, getSafeAreaInsets } from "@/utils/bridge";
import { TaskId } from "@/types/task";
import { getDeviceId } from "@/utils/device";
import { toggleConsole } from "@/utils/consoleControl";
import { toast } from "@/utils/toast";
import { STORAGE_KEYS } from "@/constants/storageKeys";
import { redirectToPayPalLogin } from "@/utils/cashoutPaypal";
import { showBindPaypalModal } from "@/components/BindPaypalModal";
import { showCashoutModal } from "@/components/showCashoutModal";
import mockCallManager from "@/utils/mockCallManager";
import { MockCallType } from "@/types/call";
import { useSafeArea } from "@/hooks/useSafeArea";

// 调试用 localStorage keys
const DEBUG_KEYS = {
  PRINT_LOG: "printLog",
  CLOSE_LOG_TRANSFER: "closeLogTransfer",
  SKIP_GUIDE_VERIFY: "skip_guide_verify",
  SHORT_MODAL_CHECK: "short_modal_check",
  DEBUG_VC_MINUTES: "debug_vc_minutes",
} as const;

/** 通用输入行组件 */
interface InputRowProps {
  label: string;
  placeholder: string;
  value: string;
  onChange: (v: string) => void;
  onAction: () => void;
  actionText: string;
}

const InputRow: FC<InputRowProps> = ({ label, placeholder, value, onChange, onAction, actionText }) => (
  <div className="flex items-center gap-2 flex-wrap">
    <span className="text-sm text-gray-300 shrink-0">{label}</span>
    <input
      type="text"
      placeholder={placeholder}
      value={value}
      onChange={(e) => onChange(e.target.value)}
      className="flex-1 min-w-[120px] px-3 py-2 rounded-lg bg-gray-800 border border-gray-700 text-white text-sm outline-none focus:border-blue-500"
    />
    <button onClick={onAction} className="px-4 py-2 bg-blue-600 text-white text-sm rounded-lg active:bg-blue-700">
      {actionText}
    </button>
  </div>
);

/** 开关行组件 - 用 flex + margin 替代 position */
interface SwitchRowProps {
  label: string;
  checked: boolean;
  onChange: (v: boolean) => void;
}

const SwitchRow: FC<SwitchRowProps> = ({ label, checked, onChange }) => (
  <div className="flex items-center justify-between gap-2">
    <span className="text-sm text-gray-300">{label}</span>
    <button
      onClick={() => onChange(!checked)}
      className={`flex items-center w-11 h-6 rounded-full p-0.5 transition-colors ${checked ? "bg-blue-600 justify-end" : "bg-gray-600 justify-start"}`}
    >
      <span className="w-5 h-5 bg-white rounded-full" />
    </button>
  </div>
);

/** 分组标题 */
const SectionTitle: FC<{ title: string }> = ({ title }) => (
  <h3 className="text-xs font-semibold text-gray-500 uppercase tracking-wider mt-4 mb-2">{title}</h3>
);

/** 信息展示行 */
const InfoRow: FC<{
  label: string;
  value: string;
  onCopy?: (text: string) => void;
  truncate?: boolean;
}> = ({ label, value, onCopy, truncate }) => (
  <div className="flex items-center gap-2 text-sm">
    <span className="text-gray-500 shrink-0 w-28">{label}:</span>
    <span className={`text-gray-200 ${truncate ? "truncate max-w-[200px]" : ""}`}>{value}</span>
    {onCopy && (
      <button
        onClick={() => onCopy(value)}
        className="ml-auto text-xs text-blue-400 px-2 py-1 rounded bg-blue-600/10 active:bg-blue-600/20 shrink-0"
      >
        Copy
      </button>
    )}
  </div>
);

/** 操作按钮 */
const VARIANT_CLASS = {
  default: "bg-gray-800 text-white active:bg-gray-700",
  warning: "bg-yellow-600/20 text-yellow-400 active:bg-yellow-600/30",
  danger: "bg-red-600/20 text-red-400 active:bg-red-600/30",
} as const;

const ActionButton: FC<{
  label: string;
  onClick: () => void;
  variant?: keyof typeof VARIANT_CLASS;
}> = ({ label, onClick, variant = "default" }) => (
  <button onClick={onClick} className={`px-4 py-2 text-sm rounded-lg ${VARIANT_CLASS[variant]}`}>
    {label}
  </button>
);

const DebugPage: FC = () => {
  const navigate = useNavigate();
  const { userInfo, token, deleteAccount, logout, fetchPaypalAccount } = useUser();
  const { finishTask: doFinishTask } = useTask();
  const safeArea = useSafeArea();
  const [bridgeSafeArea, setBridgeSafeArea] = useState("");

  // rerender-lazy-state-init: 调试状态
  const [printLog, setPrintLog] = useState(() => localStorage.getItem(DEBUG_KEYS.PRINT_LOG) === "1");
  const [vConsoleEnabled, setVConsoleEnabled] = useState(() => {
    const flag = localStorage.getItem(STORAGE_KEYS.DEBUG_VCONSOLE);
    return flag !== null ? flag === "1" : import.meta.env.MODE !== "production";
  });
  const [skipGuideVerify, setSkipGuideVerify] = useState(
    () => localStorage.getItem(DEBUG_KEYS.SKIP_GUIDE_VERIFY) === "1",
  );
  const [shortModalCheck, setShortModalCheck] = useState(
    () => localStorage.getItem(DEBUG_KEYS.SHORT_MODAL_CHECK) === "1",
  );
  const [isAllChatList, setIsAllChatList] = useState(
    () => localStorage.getItem(STORAGE_KEYS.DEV_IS_ALL_CHAT_LIST) === "1",
  );
  const [disableValidation, setDisableValidation] = useState(
    () => localStorage.getItem(STORAGE_KEYS.DEBUG_DISABLE_VALIDATION) === "1",
  );
  const [autoMockEnabled, setAutoMockEnabled] = useState(
    () => localStorage.getItem(STORAGE_KEYS.DEBUG_DISABLE_AUTO_MOCK) !== "1",
  );
  const [vcMinutes, setVcMinutes] = useState(() => localStorage.getItem(DEBUG_KEYS.DEBUG_VC_MINUTES) || "");
  const [latitude, setLatitude] = useState("");
  const [longitude, setLongitude] = useState("");
  const [voipPeerUserId, setVoipPeerUserId] = useState("");
  const [taskId, setTaskId] = useState("");
  const [deviceId, setDeviceId] = useState("");
  const [mockPrice, setMockPrice] = useState("0.6");

  // rerender-use-callback: 稳定回调引用
  const copyToClipboard = useCallback(async (text: string) => {
    try {
      await navigator.clipboard.writeText(text);
      toast.success("已复制到剪贴板");
    } catch {
      toast.error("复制失败");
    }
  }, []);

  const handleDeletePaypal = useCallback(async () => {
    if (!userInfo?.userId) return toast.error("未获取到 UserId");
    if (!window.confirm("确定要删除自己的 PayPal 账号吗？")) return;
    try {
      const res = await adminDeletePaypalId(userInfo.userId);
      if (res.code === UserServiceCommonCode.Success) {
        await fetchPaypalAccount(); // 同步清空 store
        toast.success("Delete PayPal success");
      } else {
        toast.error("Delete PayPal failed");
      }
    } catch {
      toast.error("Delete PayPal failed");
    }
  }, [userInfo?.userId, fetchPaypalAccount]);

  const handleDeleteAccount = useCallback(async () => {
    if (!window.confirm("确定要删除账户吗？此操作不可逆！")) return;
    const success = await deleteAccount();
    if (success) {
      logout();
      window.location.replace("/onboarding");
    } else {
      toast.error("删除账户失败");
    }
  }, [deleteAccount, logout]);

  const handleGetDeviceId = useCallback(async () => {
    const id = await getDeviceId();
    setDeviceId(id);
    toast.info(`DeviceId: ${id}`);
  }, []);

  return (
    <div className="h-full bg-gray-950 text-white p-4 pt-[calc(var(--sat,0px)+16px)] pb-20 overflow-y-auto">
      {/* Header */}
      <div className="flex items-center gap-3 mb-4">
        <button onClick={() => navigate(-1)} className="text-2xl">
          ←
        </button>
        <h1 className="text-xl font-bold">Debug</h1>
        <span className="ml-auto text-xs px-2 py-1 rounded bg-red-600/20 text-red-400">
          {isApp() ? "APK WebView" : "H5"}
        </span>
      </div>

      <div className="space-y-3">
        {/* ===== 用户信息 ===== */}
        <SectionTitle title="用户信息" />
        <InfoRow label="UserId" value={String(userInfo?.userId ?? "N/A")} onCopy={copyToClipboard} />
        <InfoRow label="Username" value={userInfo?.username ?? "N/A"} />
        <InfoRow label="App Version" value={import.meta.env.VITE_APP_VERSION ?? "unknown"} />
        <InfoRow label="Build Number" value={import.meta.env.VITE_BUILD_NUMBER ?? "unknown"} />
        <InfoRow label="是否视频小利女" value={userInfo?.isVideoTest ? "是" : "否"} />
        <InfoRow label="Token" value={token ?? "N/A"} onCopy={copyToClipboard} truncate />

        {/* DeviceId */}
        <div className="flex items-center gap-2">
          <button onClick={handleGetDeviceId} className="px-3 py-2 bg-gray-800 text-sm rounded-lg active:bg-gray-700">
            获取 DeviceId
          </button>
          {deviceId && (
            <span className="text-xs text-gray-400 truncate flex-1" onClick={() => copyToClipboard(deviceId)}>
              {deviceId}
            </span>
          )}
        </div>

        {/* ===== 日志控制 ===== */}
        <SectionTitle title="日志控制" />
        <div className="space-y-3 bg-gray-900 rounded-xl p-4">
          <SwitchRow
            label="开启 Console 日志"
            checked={printLog}
            onChange={(v) => {
              setPrintLog(v);
              toggleConsole(v);
              toast.success(v ? "日志已开启" : "日志已关闭");
            }}
          />
          <SwitchRow
            label="vConsole 调试面板"
            checked={vConsoleEnabled}
            onChange={(v) => {
              setVConsoleEnabled(v);
              localStorage.setItem(STORAGE_KEYS.DEBUG_VCONSOLE, v ? "1" : "0");
              toast.success(v ? "vConsole 已开启，刷新页面生效" : "vConsole 已关闭，刷新页面生效");
            }}
          />
        </div>

        {/* ===== 通话调试 ===== */}
        <SectionTitle title="通话调试" />
        <div className="space-y-3 bg-gray-900 rounded-xl p-4">
          <div className="flex items-center gap-2">
            <span className="text-sm text-gray-300 shrink-0">Mock 价格</span>
            <input
              type="text"
              placeholder="$/min"
              value={mockPrice}
              onChange={(e) => setMockPrice(e.target.value)}
              className="w-20 px-3 py-2 rounded-lg bg-gray-800 border border-gray-700 text-white text-sm outline-none focus:border-blue-500"
            />
            <span className="text-xs text-gray-500">$/min</span>
          </div>
          <div className="flex gap-2 flex-wrap">
            <ActionButton
              label="Normal Mock"
              onClick={() => {
                const price = parseFloat(mockPrice) || 0;
                mockCallManager.startMockCall(MockCallType.Normal, price);
                toast.info(`Normal Mock (price: $${price})`);
              }}
            />
            <ActionButton
              label="Guide Mock"
              onClick={() => {
                const price = parseFloat(mockPrice) || 0;
                mockCallManager.startMockCall(MockCallType.Guide, price);
                toast.info(`Guide Mock (price: $${price})`);
              }}
            />
            <ActionButton
              label="Dispatch Mock"
              onClick={() => {
                const price = parseFloat(mockPrice) || 0;
                mockCallManager.startMockCall(MockCallType.Dispatch, price);
                toast.info(`Dispatch Mock (price: $${price})`);
              }}
            />
          </div>
        </div>
        <InputRow
          label="VOIP Peer"
          placeholder="输入 User ID"
          value={voipPeerUserId}
          onChange={setVoipPeerUserId}
          onAction={() => {
            if (!voipPeerUserId) return toast.error("请输入 User ID");
            localStorage.setItem("debug_voip_peer_user_id", voipPeerUserId);
            toast.success(`VOIP Peer 已设置: ${voipPeerUserId}`);
          }}
          actionText="设置"
        />
        <InputRow
          label="VC 分钟数"
          placeholder="视频通话分钟数"
          value={vcMinutes}
          onChange={setVcMinutes}
          onAction={() => {
            if (vcMinutes) {
              localStorage.setItem(DEBUG_KEYS.DEBUG_VC_MINUTES, vcMinutes);
            } else {
              localStorage.removeItem(DEBUG_KEYS.DEBUG_VC_MINUTES);
            }
            toast.success("视频通话配置已更新");
          }}
          actionText="配置"
        />

        {/* ===== 任务调试 ===== */}
        <SectionTitle title="任务调试" />
        <InputRow
          label="Task ID"
          placeholder="输入 Task ID"
          value={taskId}
          onChange={setTaskId}
          onAction={async () => {
            if (!taskId) return toast.error("请输入 Task ID");
            const id = Number(taskId);
            if (isNaN(id)) return toast.error("Task ID 必须是数字");
            const success = await doFinishTask(id as TaskId);
            if (success) {
              toast.success(`任务 ${taskId} 已完成`);
            } else {
              toast.error(`任务 ${taskId} 完成失败`);
            }
          }}
          actionText="完成任务"
        />

        {/* ===== 提现 / 位置调试 ===== */}
        <SectionTitle title="提现 / 位置调试" />
        <div className="flex gap-2 flex-wrap">
          <ActionButton label="PayPal 授权测试" onClick={() => redirectToPayPalLogin()} />
          <ActionButton label="PayPal 邮箱绑定弹窗" onClick={() => showBindPaypalModal({ amount: "10.00" })} />
          <ActionButton label="提现提醒弹窗" onClick={() => showCashoutModal({ amount: "10.00", progress: 80 })} />
        </div>
        <div className="flex items-center gap-2 flex-wrap">
          <input
            type="text"
            placeholder="纬度 (latitude)"
            value={latitude}
            onChange={(e) => setLatitude(e.target.value)}
            className="flex-1 min-w-[100px] px-3 py-2 rounded-lg bg-gray-800 border border-gray-700 text-white text-sm outline-none focus:border-blue-500"
          />
          <input
            type="text"
            placeholder="经度 (longitude)"
            value={longitude}
            onChange={(e) => setLongitude(e.target.value)}
            className="flex-1 min-w-[100px] px-3 py-2 rounded-lg bg-gray-800 border border-gray-700 text-white text-sm outline-none focus:border-blue-500"
          />
          <button
            onClick={() => {
              const lat = parseFloat(latitude);
              const lng = parseFloat(longitude);
              if (isNaN(lat) || isNaN(lng)) return toast.error("请输入有效的经纬度");
              localStorage.setItem("debug_latitude", String(lat));
              localStorage.setItem("debug_longitude", String(lng));
              toast.success("经纬度已更新");
            }}
            className="px-4 py-2 bg-blue-600 text-white text-sm rounded-lg active:bg-blue-700"
          >
            确定
          </button>
        </div>

        {/* ===== 功能开关 ===== */}
        <SectionTitle title="功能开关" />
        <div className="space-y-3 bg-gray-900 rounded-xl p-4">
          <SwitchRow
            label="跳过引导验证"
            checked={skipGuideVerify}
            onChange={(v) => {
              setSkipGuideVerify(v);
              localStorage.setItem(DEBUG_KEYS.SKIP_GUIDE_VERIFY, v ? "1" : "0");
            }}
          />
          <SwitchRow
            label="显示所有聊天列表"
            checked={isAllChatList}
            onChange={(v) => {
              setIsAllChatList(v);
              localStorage.setItem(STORAGE_KEYS.DEV_IS_ALL_CHAT_LIST, v ? "1" : "0");
            }}
          />
          <SwitchRow
            label="弹窗校验 (5分钟)"
            checked={shortModalCheck}
            onChange={(v) => {
              setShortModalCheck(v);
              localStorage.setItem(DEBUG_KEYS.SHORT_MODAL_CHECK, v ? "1" : "0");
            }}
          />
          <SwitchRow
            label="禁用地区校验 (country_code & locale)"
            checked={disableValidation}
            onChange={(v) => {
              setDisableValidation(v);
              localStorage.setItem(STORAGE_KEYS.DEBUG_DISABLE_VALIDATION, v ? "1" : "0");
            }}
          />
          <SwitchRow
            label="自动弹出 Mock 视频"
            checked={autoMockEnabled}
            onChange={(v) => {
              setAutoMockEnabled(v);
              localStorage.setItem(STORAGE_KEYS.DEBUG_DISABLE_AUTO_MOCK, v ? "0" : "1");
              toast.success(v ? "自动 Mock 已开启" : "自动 Mock 已关闭");
            }}
          />
        </div>

        {/* ===== 工具 ===== */}
        <SectionTitle title="工具" />
        <div className="flex gap-2 flex-wrap">
          <ActionButton
            label="下载 APK"
            onClick={() => {
              const url = import.meta.env.VITE_APK_DOWNLOAD_URL;
              if (!url) return toast.error("未配置 VITE_APK_DOWNLOAD_URL");
              window.open(url, "_blank");
              toast.info("正在下载 APK...");
            }}
          />
          <ActionButton
            label="打开邮件客户端"
            onClick={() => {
              openEmailClient("contact@gracechat.com");
              toast.info("正在打开邮件客户端...");
            }}
          />
          <ActionButton
            label="清除 LocalStorage"
            variant="warning"
            onClick={() => {
              if (!window.confirm("确定清除所有 localStorage？")) return;
              localStorage.clear();
              toast.success("LocalStorage 已清除");
            }}
          />
        </div>

        {/* ===== 危险操作 ===== */}
        <SectionTitle title="危险操作" />
        <div className="flex gap-2 flex-wrap">
          <ActionButton label="Delete PayPal" variant="warning" onClick={handleDeletePaypal} />
          <ActionButton label="删除账户" variant="danger" onClick={handleDeleteAccount} />
          <ActionButton
            label="退出登录"
            variant="danger"
            onClick={() => {
              if (!window.confirm("确定退出登录？")) return;
              logout();
              window.location.replace("/onboarding");
            }}
          />
        </div>

        {/* ===== 安全区域调试 ===== */}
        <SectionTitle title="安全区域 (Safe Area)" />
        <div className="bg-gray-900 rounded-xl p-4 space-y-1 text-xs text-gray-400">
          <p>
            Hook: top={safeArea.top} right={safeArea.right} bottom={safeArea.bottom} left={safeArea.left}
          </p>
          <p>CSS --sat: {getComputedStyle(document.documentElement).getPropertyValue("--sat")}</p>
          {bridgeSafeArea && <p>Bridge: {bridgeSafeArea}</p>}
        </div>
        <ActionButton
          label="测试 Bridge getSafeAreaInsets"
          onClick={async () => {
            const result = await getSafeAreaInsets();
            const text = result
              ? `top=${result.top} right=${result.right} bottom=${result.bottom} left=${result.left}`
              : "undefined (bridge 不可用)";
            setBridgeSafeArea(text);
            toast.info(`Bridge: ${text}`);
          }}
        />

        {/* ===== 环境信息 ===== */}
        <SectionTitle title="环境信息" />
        <div className="bg-gray-900 rounded-xl p-4 space-y-1 text-xs text-gray-400">
          <p>Mode: {import.meta.env.MODE}</p>
          <p>Base URL: {import.meta.env.BASE_URL}</p>
          <p>API Base: {import.meta.env.VITE_API_BASE_URL ?? "/api"}</p>
          <p>isApp: {String(isApp())}</p>
          <p>UserAgent: {navigator.userAgent}</p>
        </div>
      </div>
    </div>
  );
};

export default DebugPage;
